-- تصحيح ترتيب مؤشر 1-2-1-6 (كان orderIndex=0، يجب أن يكون 6)
UPDATE indicators SET orderIndex = 6 WHERE code = '1-2-1-6';

-- تصحيح نص مؤشرات قيادة العملية التعليمية بالضبط من الصورة
UPDATE indicators SET text = 'تعزِّز المدرسة القيم الإسلامية والهوية الوطنية.' WHERE code = '1-2-1-1';
UPDATE indicators SET text = 'تلتزم المدرسة بقيم مهنة التعليم وأخلاقياتها.' WHERE code = '1-2-1-2';
UPDATE indicators SET text = 'توفِّر المدرسة مناخاً آمناً للتعلم والنمو نفسياً واجتماعياً.' WHERE code = '1-2-1-3';
UPDATE indicators SET text = 'تنشر المدرسة قواعد السلوك والمواطنة، وتتابع تطبيقها.' WHERE code = '1-2-1-4';
UPDATE indicators SET text = 'توفِّر المدرسة برامج وأنشطة تربوية داعمة للسلوك الإيجابي.' WHERE code = '1-2-1-5';
UPDATE indicators SET text = 'توفِّر المدرسة برامج وأنشطة إثرائية غير صفية؛ لتطوير مواهب الأطفال، وتهيئتهم للمستقبل.' WHERE code = '1-2-1-6';

-- تصحيح مؤشرات المجتمع المدرسي
UPDATE indicators SET text = 'تعزِّز المدرسة بناء العلاقات الإيجابية والتعاون في المجتمع المدرسي.' WHERE code = '1-3-1-1';
UPDATE indicators SET text = 'تعزِّز المدرسة مشاركة الأسرة في تعلم أطفالهم، والتحضير للمستقبل.' WHERE code = '1-3-1-2';
UPDATE indicators SET text = 'تعزِّز المدرسة الشراكة المجتمعية لدعم التعلم والتأثير الإيجابي في المجتمع.' WHERE code = '1-3-1-3';

